const secret = $input.first().headers?.['x-webhook-secret'] || '';
if (secret !== 'YOUR_WEBHOOK_SECRET') throw new Error('Unauthorized');

const body = $input.first().json.body || $input.first().json;
const clientId = body.clientId || body.client_id || '';
const dateRange = body.dateRange || 'this_month';

const now = $now;
let periodStart, periodEnd, prevStart, prevEnd;

switch (dateRange) {
  case 'last_month': {
    const lastMonthEnd = now.startOf('month').minus({ days: 1 });
    const lastMonthStart = lastMonthEnd.startOf('month');
    periodStart = lastMonthStart.toFormat('yyyy-MM-dd');
    periodEnd = lastMonthEnd.toFormat('yyyy-MM-dd');
    const prevMonthEnd = lastMonthStart.minus({ days: 1 });
    prevStart = prevMonthEnd.startOf('month').toFormat('yyyy-MM-dd');
    prevEnd = prevMonthEnd.toFormat('yyyy-MM-dd');
    break;
  }
  case 'q1': {
    const year = now.year;
    periodStart = `${year}-01-01`;
    periodEnd = `${year}-03-31`;
    prevStart = `${year - 1}-01-01`;
    prevEnd = `${year - 1}-03-31`;
    break;
  }
  case 'last_90': {
    periodEnd = now.toFormat('yyyy-MM-dd');
    periodStart = now.minus({ days: 90 }).toFormat('yyyy-MM-dd');
    prevEnd = now.minus({ days: 91 }).toFormat('yyyy-MM-dd');
    prevStart = now.minus({ days: 180 }).toFormat('yyyy-MM-dd');
    break;
  }
  case 'ytd': {
    periodStart = `${now.year}-01-01`;
    periodEnd = now.toFormat('yyyy-MM-dd');
    prevStart = `${now.year - 1}-01-01`;
    prevEnd = `${now.year - 1}-${now.toFormat('MM-dd')}`;
    break;
  }
  default: { // this_month
    periodStart = now.startOf('month').toFormat('yyyy-MM-dd');
    periodEnd = now.toFormat('yyyy-MM-dd');
    const prevMonthEnd = now.startOf('month').minus({ days: 1 });
    prevStart = prevMonthEnd.startOf('month').toFormat('yyyy-MM-dd');
    prevEnd = prevMonthEnd.toFormat('yyyy-MM-dd');
  }
}

return [{ json: { clientId, dateRange, periodStart, periodEnd, prevStart, prevEnd } }];

const params   = $('Compute Date Window').first().json;
const clientRec = $('Get Client Record').first()?.json || {};
const currKpis  = $('Get Current KPIs').all().map(i => i.json);
const prevKpis  = $('Get Previous KPIs').all().map(i => i.json);
const revRows   = $('Get Revenue Data').all().map(i => i.json);
const channels  = $('Get Channel Performance').all().map(i => i.json);
const campaigns = $('Get Campaigns').all().map(i => i.json);
const summaryRec = $('Get AI Summary').first()?.json || {};

// ── Aggregate current KPIs ──
const currRevenue = currKpis.reduce((s, r) => s + (r.total_revenue || 0), 0);
const currSpend   = currKpis.reduce((s, r) => s + (r.ad_spend || 0), 0);
const currOrders  = currKpis.reduce((s, r) => s + (r.total_orders || 0), 0);
const currSess    = currKpis.reduce((s, r) => s + (r.total_sessions || 0), 0);
const currRoas    = currSpend > 0 ? parseFloat((currRevenue / currSpend).toFixed(2)) : 0;
const currConv    = currSess > 0  ? parseFloat(((currOrders / currSess) * 100).toFixed(2)) : 0;

// ── Aggregate previous KPIs ──
const prevRevenue = prevKpis.reduce((s, r) => s + (r.total_revenue || 0), 0);
const prevSpend   = prevKpis.reduce((s, r) => s + (r.ad_spend || 0), 0);
const prevOrders  = prevKpis.reduce((s, r) => s + (r.total_orders || 0), 0);
const prevSess    = prevKpis.reduce((s, r) => s + (r.total_sessions || 0), 0);
const prevRoas    = prevSpend > 0 ? parseFloat((prevRevenue / prevSpend).toFixed(2)) : 0;
const prevConv    = prevSess > 0  ? parseFloat(((prevOrders / prevSess) * 100).toFixed(2)) : 0;

function pct(curr, prev) {
  if (!prev) return 0;
  return parseFloat(((curr - prev) / prev * 100).toFixed(1));
}

// ── Revenue trend (group current by week_label) ──
const weekMap = {};
for (const r of revRows) {
  const label = r.week_label || r.week_start || 'Unknown';
  if (!weekMap[label]) weekMap[label] = { label, value: 0 };
  weekMap[label].value += r.revenue || 0;
}

// Build prev-period weekly revenue from daily KPI snapshots
const prevWeekRevMap = {};
for (const r of prevKpis) {
  if (!r.snapshot_date) continue;
  const d = new Date(r.snapshot_date + 'T00:00:00Z');
  const dow = d.getUTCDay();
  d.setUTCDate(d.getUTCDate() + (dow === 0 ? -6 : 1 - dow));
  const weekKey = d.toISOString().split('T')[0];
  if (!prevWeekRevMap[weekKey]) prevWeekRevMap[weekKey] = 0;
  prevWeekRevMap[weekKey] += r.total_revenue || 0;
}
const prevWeekValues = Object.values(prevWeekRevMap).map(v => parseFloat(v.toFixed(2)));

const revenueData = Object.values(weekMap).map((w, i) => ({
  label: w.label,
  value: parseFloat(w.value.toFixed(2)),
  prev: prevWeekValues[i] || 0
}));

// ── Channel data ──
const totalChRevenue = channels.reduce((s, ch) => s + (ch.total_revenue || 0), 0);
const channelData = channels.map(ch => ({
  name:        ch.channel,
  percentage:  totalChRevenue > 0 ? Math.round((ch.total_revenue / totalChRevenue) * 100) : 0,
  spend:       parseFloat((ch.total_spend   || 0).toFixed(2)),
  revenue:     parseFloat((ch.total_revenue || 0).toFixed(2)),
  roas:        parseFloat((ch.roas          || 0).toFixed(2)),
  barWidthPct: ch.bar_width_pct || 50,
  convRate:    parseFloat((ch.avg_conv_rate || 0).toFixed(1))
}));

// ── Campaigns ──
const campaignData = campaigns.map(c => ({
  id:          c.campaign_id || '',
  name:        c.campaign_name || '',
  platform:    c.platform || '',
  spend:       parseFloat((c.spend       || 0).toFixed(2)),
  revenue:     parseFloat((c.revenue     || 0).toFixed(2)),
  roas:        parseFloat((c.roas        || c.revenue / (c.spend || 1)).toFixed(2)),
  status:      c.status || 'Active',
  impressions: c.impressions || 0,
  clicks:      c.clicks      || 0,
  ctr:         parseFloat((c.ctr || 0).toFixed(1)),
  cpc:         parseFloat((c.cpc || 0).toFixed(2))
}));

// ── AI Summary ──
const aiSummary = {
  bodyHtml: summaryRec.body_html || '<p>AI summary will appear after the next weekly report generation.</p>',
  win:   { title: summaryRec.insight_1_title || 'Win',        text: summaryRec.insight_1_text || '' },
  watch: { title: summaryRec.insight_2_title || 'Watch',      text: summaryRec.insight_2_text || '' },
  next:  { title: summaryRec.insight_3_title || 'Next Steps', text: summaryRec.insight_3_text || '' }
};

// ── Client metadata ──
const name = clientRec.company_name || params.clientId;
const initials = name.split(' ').map(w => w[0]).join('').slice(0, 2).toUpperCase();

return [{
  json: {
    client: {
      id:       params.clientId,
      name,
      niche:    clientRec.niche || '',
      color:    clientRec.brand_color || '#6366f1',
      initials
    },
    kpis: {
      revenue:          parseFloat(currRevenue.toFixed(2)),
      revenueChange:    pct(currRevenue, prevRevenue),
      conversionRate:   currConv,
      conversionChange: parseFloat((currConv - prevConv).toFixed(2)),
      adSpend:          parseFloat(currSpend.toFixed(2)),
      adSpendChange:    pct(currSpend, prevSpend),
      roas:             currRoas,
      roasChange:       parseFloat((currRoas - prevRoas).toFixed(2))
    },
    revenueData,
    channels: channelData,
    campaigns: campaignData,
    aiSummary,
    lastSynced: new Date().toISOString()
  }
}];

const secret = $input.first().headers?.['x-webhook-secret'] || '';
if (secret !== 'YOUR_WEBHOOK_SECRET') throw new Error('Unauthorized');

const clients = $input.all().map(item => {
  const c = item.json;
  const name = c.company_name || '';
  const initials = name.split(' ').map(w => w[0]).join('').slice(0, 2).toUpperCase();
  return {
    id:            c.client_id,
    name,
    niche:         c.niche || '',
    color:         c.brand_color || '#6366f1',
    initials,
    campaignCount: 0  // optionally join with Campaigns count
  };
});
return [{ json: clients }];
